// Pull all invoices
const invoices = $('List Week Invoices').all().map(i => i.json);
const expenses = $('List Week Expenses').all().map(e => e.json);
const weekLabel = $('Calculate Week Range').item.json.weekLabel;

// Revenue metrics
const paidInvoices = invoices.filter(i => i.status === 'paid');
const pendingInvoices = invoices.filter(i => ['sent', 'draft'].includes(i.status));
const overdueInvoices = invoices.filter(i => i.status === 'overdue');

const revenue = paidInvoices.reduce((s, i) => s + (i.total || 0), 0);
const pending = pendingInvoices.reduce((s, i) => s + (i.total || 0), 0);
const overdue = overdueInvoices.reduce((s, i) => s + (i.total || 0), 0);

// Expense metrics
const totalExpenses = expenses.reduce((s, e) => s + (e.amount || 0), 0);

// Profit
const netProfit = revenue - totalExpenses;
const profitMargin = revenue > 0 ? ((netProfit / revenue) * 100).toFixed(1) : 0;

// Top clients by revenue this week
const clientRevenue = {};
paidInvoices.forEach(inv => {
  const name = inv.clientName || 'Unknown';
  clientRevenue[name] = (clientRevenue[name] || 0) + (inv.total || 0);
});
const topClients = Object.entries(clientRevenue)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([name, amount]) => `${name}: €${amount.toFixed(2)}`)
  .join('\n');

// Emoji for profit trend
const profitEmoji = netProfit > 0 ? '📈' : netProfit === 0 ? '➡️' : '📉';

const slackMessage = [
  `*Frihet Weekly Digest — ${weekLabel}* ${profitEmoji}`,
  '',
  '*Revenue*',
  `• Collected: *€${revenue.toFixed(2)}* (${paidInvoices.length} invoices)`,
  `• Pending: €${pending.toFixed(2)} (${pendingInvoices.length} invoices)`,
  `• Overdue: €${overdue.toFixed(2)} (${overdueInvoices.length} invoices)`,
  '',
  '*Expenses*',
  `• Total: *€${totalExpenses.toFixed(2)}* (${expenses.length} records)`,
  '',
  '*Bottom Line*',
  `• Net Profit: *€${netProfit.toFixed(2)}*`,
  `• Margin: ${profitMargin}%`,
  '',
  topClients ? `*Top Clients*\n${topClients}` : '',
  '',
  `_Generated by <https://app.frihet.io|Frihet ERP>_`
].filter(Boolean).join('\n');

return [{ json: { slackMessage, weekLabel, revenue, totalExpenses, netProfit, profitMargin } }];
